-- Estimate templates — ready-made bundles of works for a typical job.
-- The master picks one when creating an estimate; positions are dropped in with
-- names+units, quantities left EMPTY (filled per object), prices substituted from
-- the master's OWN catalog by name match at apply-time (see EstimateTemplateService).
--
-- 88 system defaults (is_default=true, owner_id=null) parsed from
-- default-templates.md; each position's unit resolved by matching its name against
-- the default catalog (majstr-default-catalog.csv). Masters also save their own
-- (is_default=false, owner_id set) via "save estimate as template".

CREATE TABLE estimate_templates (
    id          UUID PRIMARY KEY,
    owner_id    UUID REFERENCES users(id) ON DELETE CASCADE,   -- null = system default
    name        VARCHAR(255) NOT NULL,
    trade       VARCHAR(50),                                   -- null = general
    is_default  BOOLEAN NOT NULL DEFAULT FALSE,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
    CONSTRAINT estimate_templates_trade_check CHECK (trade IS NULL OR trade IN ('ELECTRICAL', 'PLUMBING', 'TILING', 'BUILDER', 'PAINTER', 'DRYWALL', 'FLOORING', 'DEMOLITION', 'GENERAL', 'OTHER')),
    -- a default has no owner; an owned template must have one
    CONSTRAINT estimate_templates_owner_check CHECK (
        (is_default AND owner_id IS NULL) OR (NOT is_default AND owner_id IS NOT NULL))
);
CREATE INDEX idx_estimate_templates_owner ON estimate_templates(owner_id);
-- the default-template fetch is "is_default = true, optionally filtered by trade"
CREATE INDEX idx_estimate_templates_default ON estimate_templates(trade) WHERE is_default = TRUE;

CREATE TABLE estimate_template_items (
    id          UUID PRIMARY KEY,
    template_id UUID NOT NULL REFERENCES estimate_templates(id) ON DELETE CASCADE,
    name        VARCHAR(255) NOT NULL,
    type        VARCHAR(20) NOT NULL,
    unit        VARCHAR(20) NOT NULL,
    sort_order  INT NOT NULL DEFAULT 0,
    CONSTRAINT estimate_template_items_type_check CHECK (type IN ('WORK', 'MATERIAL')),
    CONSTRAINT estimate_template_items_unit_check CHECK (unit IN ('M2', 'M', 'LINEAR_METER', 'PIECE', 'KG', 'HOUR', 'SET', 'M3', 'T', 'POINT', 'PERCENT'))
);
CREATE INDEX idx_estimate_template_items_template ON estimate_template_items(template_id);


